{"code": "import json

# Load literature & fiction books
lit_fiction_var = locals()['var_functions.query_db:22']
if isinstance(lit_fiction_var, str):
    with open(lit_fiction_var, 'r') as f:
        lit_fiction_books = json.load(f)
else:
    lit_fiction_books = lit_fiction_var

# Load all reviews
reviews_var = locals()['var_functions.query_db:24']
if isinstance(reviews_var, str):
    with open(reviews_var, 'r') as f:
        reviews = json.load(f)
else:
    reviews = reviews_var

# Debug: Check the structure
book_ids = [book['book_id'] for book in lit_fiction_books]

# Match reviews by mapping purchase_id to book_id
book_ratings = {}
for review in reviews:
    purchase_id = review['purchase_id']
    # Try to extract book number from purchase_id
    if purchase_id.startswith('purchaseid_'):
        book_num = purchase_id.replace('purchaseid_', '')
        # Create book_id in the same format as books_info
        book_id = f'bookid_{book_num}'
        if book_id in book_ids:
            if book_id not in book_ratings:
                book_ratings[book_id] = []
            book_ratings[book_id].append(float(review['rating']))

# Calculate average ratings and find books with 5.0 average
perfect_books = []
for book in lit_fiction_books:
    book_id = book['book_id']
    if book_id in book_ratings and book_ratings[book_id]:
        avg_rating = sum(book_ratings[book_id]) / len(book_ratings[book_id])
        if abs(avg_rating - 5.0) < 0.001:  # Check if average is 5.0
            perfect_books.append({
                'book_id': book_id,
                'title': book['title'],
                'categories': book['categories'],
                'avg_rating': avg_rating,
                'review_count': len(book_ratings[book_id])
            })

print('__RESULT__:')
print(json.dumps({
    'perfect_books': perfect_books,
    'total_lit_fiction_books': len(lit_fiction_books),
    'books_with_reviews': len(book_ratings)
}, indent=2))"}

